request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  (COUNT(DISTINCT ?task) AS ?taskCount)
  (COUNT(DISTINCT ?taskOp) AS ?executableTaskCount)
  (COUNT(DISTINCT ?taskNotOp) AS ?nonExecutableTaskCount)
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "262d9e9b8c224d918fe800cd2a454ddf" ;
         tai:belongsTo ?org .

  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .

  OPTIONAL {
    ?task tai:belongsTo ?choreo2 .
    ?task bboExt:loopType ?loopType .
    FILTER(?loopType IN ("None","Standard","MultiInstanceSequential","MultiInstanceParallel"))
    BIND(?task AS ?taskOp)
  }

  OPTIONAL {
    ?task bboExt:loopType ?loopType2 .
    FILTER(!(?loopType2 IN ("None","Standard","MultiInstanceSequential","MultiInstanceParallel")))
    BIND(?task AS ?taskNotOp)
  }

  FILTER(!BOUND(?taskOp) || !BOUND(?taskNotOp))
}
